/// The exact row a supplier-quotation line insert writes.
pub struct NewSupplierQuotationItemRow {
    pub id: Uuid,
    pub quotation_id: Uuid,
    pub company_id: Uuid,
    pub item_id: Uuid,
    pub quantity: Decimal,
    pub rate: Decimal,
}

/// A quoted line, as copied forward by the SQ→PO funnel step.
pub struct QuotedLineRow {
    pub item_id: Uuid,
    pub quantity: Decimal,
    pub rate: Decimal,
}

/// Hand-written SupplierQuotationItem SQL. Lives here (not in the write service) per the module's
/// 4-layer rule.
impl SupplierQuotationItemRepository {
    /// Insert one quoted line.
    ///
    /// Takes the CALLER'S connection so it commits with its header. The caller has already bound the
    /// company on it (`bind_company_on`) — don't re-bind here.
    pub async fn insert_item(
        &self,
        conn: &mut sqlx::PgConnection,
        l: &NewSupplierQuotationItemRow,
    ) -> Result<(), sqlx::Error> {
        sqlx::query(
            "INSERT INTO buying.supplier_quotation_items (id, quotation_id, company_id, item_id, quantity, rate) VALUES ($1,$2,$3,$4,$5,$6)",
        )
        .bind(l.id).bind(l.quotation_id).bind(l.company_id).bind(l.item_id).bind(l.quantity).bind(l.rate)
        .execute(conn)
        .await?;
        Ok(())
    }

    /// Read a supplier quotation's lines for the SQ→PO conversion. ID-only + scoped read.
    pub async fn fetch_lines(
        &self,
        pool: &PgPool,
        quotation_id: Uuid,
    ) -> Result<Vec<QuotedLineRow>, sqlx::Error> {
        let rows = company_scope::fetch_all_rows_scoped(
            pool,
            sqlx::query(
                r#"SELECT item_id, quantity, rate FROM buying.supplier_quotation_items
                   WHERE quotation_id=$1 AND (metadata->>'deleted_at') IS NULL"#,
            ).bind(quotation_id),
        )
        .await?;
        Ok(rows.iter().map(|r| QuotedLineRow {
            item_id: r.get("item_id"),
            quantity: r.get("quantity"),
            rate: r.get("rate"),
        }).collect())
    }
}

